module RefModule(
  input CLK,
  input EN,
  input TE,
  output ENCLK
);reg obf_latch_out;

  always @(*) begin
    if (EN) begin
      obf_latch_out <= CLK;
    end else if (TE) begin
      obf_latch_out <= TE;
    end else begin
      obf_latch_out <= 1'b0;
    end
  end

  assign ENCLK = obf_latch_out;

endmodule
